codeExercises.solution:
// File: config.js
require('dotenv').config();

const devConfig = {
  dbURI: 'mongodb://localhost:27017/dev_db'
};

const prodConfig = {
  dbURI: process.env.PROD_DB_URI
};

const env = process.env.NODE_ENV || 'development';

let exportConfig;
if (env === 'production') {
  exportConfig = prodConfig;
} else {
  exportConfig = devConfig;
}

module.exports = exportConfig;

